#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
struct query{int l,r,id;}q[N];
struct SegTree{int len,ans,sum;}t[N<<2];
int n,m,Z,a[N],b[N],Q,B,L=1,R,Ans[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u){
    t[u].sum=t[ls(u)].sum+t[rs(u)].sum;
    t[u].ans=t[ls(u)].ans+t[rs(u)].ans;
    t[u].ans+=min(max(0,t[ls(u)].len-t[ls(u)].ans),t[rs(u)].sum-t[rs(u)].ans);
    return;
}
void build(int u,int l,int r){
    t[u].len=(r-l+1);
    if(l==r)return;
    int mid=(l+r)>>1;
    build(ls(u),l,mid);
    build(rs(u),mid+1,r);
    return;
}
void change(int u,int l,int r,int pos,int k){
    if(l==r){
        if(Z-pos<a[l])return;
        if(!t[u].sum)t[u].ans=1;
        t[u].sum+=k;
        if(!t[u].sum)t[u].ans=0;
        return;
    }
    int mid=(l+r)>>1;
    if(Z-pos<a[mid+1])change(ls(u),l,mid,pos,k);
    else change(rs(u),mid+1,r,pos,k);
    push_up(u);return;
}
bool cmp(query q1,query q2){
    if(q1.l/B!=q2.l/B)return q1.l<q2.l;
    if((q1.l/B)&1)return q1.r<q2.r;
    else return q1.r>q2.r;
}
void Add(int x){change(1,1,n,x,1);return;}
void Del(int x){change(1,1,n,x,-1);return;}
int main(){
    n=read(),m=read(),Z=read();
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<=m;i++)b[i]=read();
    sort(a+1,a+n+1);
    build(1,1,n);
    Q=read(),B=sqrt(Q);
    for(int i=1;i<=Q;i++)
        q[i].l=read(),q[i].r=read(),q[i].id=i;
    sort(q+1,q+Q+1,cmp);
    for(int i=1;i<=Q;i++){
        while(L>q[i].l)Add(b[--L]);
        while(R<q[i].r)Add(b[++R]);
        while(L<q[i].l)Del(b[L++]);
        while(R>q[i].r)Del(b[R--]);
        Ans[q[i].id]=t[1].ans;
    }
    for(int i=1;i<=Q;i++)cout<<Ans[i]<<"\n";
    return 0;
}
